define('lock',['jquery', 'helpers'], function ($, helpers) {
  function Lock(resourceUri) {
    this.uri = resourceUri;
  }
  Lock.prototype.release = function (cb, err) {
    var releaseUrl = helpers._url('release', 'Lock', 'tao');
    var options = {
      data: {
        uri: this.uri
      },
      type: 'POST',
      dataType: 'json'
    };
    $.ajax(releaseUrl, options).success(cb).fail(err);
  };
  return Lock;
});
