define('layout/search',['jquery', 'layout/actions', 'ui/searchModal', 'core/store', 'context', 'util/url', 'layout/actions/binder'], function ($, actionManager, searchModal, store, context, urlHelper, binder) {
  var searchComponent = {
    container: null,
    searchStore: null,
    panelId: '',
    init(panelId) {
      searchComponent.panelId = panelId;
      store('search').then(store => {
        store.clear();
        searchComponent.searchStore = store;
        initializeEvents();
        manageSearchStoreUpdate();
      }).catch(e => {
        actionManager.trigger('error', e);
      });
    }
  };
  function initializeEvents() {
    searchComponent.container = searchComponent.panelId ? $("#panel-".concat(searchComponent.panelId, " .action-bar .search-area")) : $('.action-bar .search-area');
    var $searchBtn = $('button.icon-find', searchComponent.container);
    var $searchInput = $('input', searchComponent.container);
    var $resultsBtn = $('button.icon-ul', searchComponent.container);
    $searchBtn.off('.searchComponent').on('click.searchComponent', () => createSearchModalInstance());
    $searchInput.off('.searchComponent').on('keypress.searchComponent', e => {
      if (e.which === 13) {
        createSearchModalInstance();
      }
    });
    $resultsBtn.off('.searchComponent').on('click.searchComponent', () => {
      searchComponent.searchStore.getItem('criterias').then(storedCriterias => createSearchModalInstance(storedCriterias, false)).catch(e => {
        actionManager.trigger('error', e);
      });
    });
    $(document).on('keydown.searchComponent', e => {
      if ($('.action-bar .search-area').closest('.content-panel').css('display') === 'flex' && e.ctrlKey && e.which == 75) {
        e.preventDefault();
        createSearchModalInstance();
      }
    });
  }
  function createSearchModalInstance(criterias) {
    var searchOnInit = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : true;
    criterias = criterias || {
      search: $('input', searchComponent.container).val()
    };
    var url = searchComponent.container.data('url');
    var placeholder = searchComponent.container.find('input').attr('placeholder');
    var rootClassUri = decodeURIComponent(urlHelper.parse(url).query.rootNode);
    var isResultPage = context.shownStructure === 'results';
    var searchModalInstance = searchModal({
      criterias,
      url,
      classesUrl: urlHelper.route('getAll', 'RestResource', 'tao'),
      classMappingUrl: urlHelper.route('getWithMapping', 'ClassMetadata', 'tao'),
      statusUrl: urlHelper.route('status', 'AdvancedSearch', 'tao'),
      searchOnInit,
      rootClassUri,
      hideResourceSelector: isResultPage,
      hideCriteria: isResultPage,
      placeholder
    });
    searchModalInstance.on('store-updated', manageSearchStoreUpdate);
    searchModalInstance.on('refresh', (id, data) => {
      var uri = !isResultPage || !data.delivery ? id : data.delivery;
      actionManager.trigger('refresh', {
        uri
      });
      isResultPage && data.delivery && searchComponent.container.data('show-result', id);
    });
  }
  function manageSearchStoreUpdate() {
    searchComponent.searchStore.getItem('context').then(storedContext => {
      if (storedContext !== context.shownStructure) {
        searchComponent.searchStore.clear();
        updateViewAfterSeachStoreUpdate();
      } else {
        var promises = [];
        promises.push(searchComponent.searchStore.getItem('criterias'));
        promises.push(searchComponent.searchStore.getItem('results'));
        return Promise.all(promises).then(values => {
          updateViewAfterSeachStoreUpdate(values[0], values[1]);
        });
      }
    }).catch(e => actionManager.trigger('error', e));
  }
  function updateViewAfterSeachStoreUpdate(storedCriterias, storedSearchResults) {
    var $searchInput = $('input', searchComponent.container);
    var $resultsCounterContainer = $('.results-counter', searchComponent.container);
    var $searchAreaButtonsContainer = $('.search-area-buttons-container', searchComponent.container);
    $searchInput.val(storedCriterias ? storedCriterias.search : '');
    if (storedSearchResults) {
      $searchAreaButtonsContainer.addClass('has-results-counter');
      $resultsCounterContainer.text(storedSearchResults.totalCount > 99 ? '+99' : storedSearchResults.totalCount);
    } else {
      $searchAreaButtonsContainer.removeClass('has-results-counter');
      $resultsCounterContainer.text('');
    }
  }
  return searchComponent;
});
