define('form/property',['jquery', 'lodash', 'form/post-render-props'], function ($, _, postRenderProps) {
  var propertyManager = {
    add: function add(classUri, url) {
      var $existingProperties = $('.property-block'),
        index = $existingProperties.length;
      $existingProperties.each(function () {
        index = Math.max(parseInt(this.id.replace(/[\D]+/, '')), index);
      });
      index++;
      $.ajax({
        url: url,
        type: "POST",
        data: {
          index: index,
          id: classUri
        },
        dataType: 'html',
        success: function success(response) {
          var $response = $(response),
            property = $response.first();
          if ($response.length > 1) {
            var script = $response.last();
            script.appendTo(property);
          }
          postRenderProps.init(property);
        }
      });
    },
    remove: function remove(uri, classUri, url, successCallback) {
      $.ajax({
        url: url,
        type: "POST",
        data: {
          uri: uri,
          classUri: classUri
        },
        dataType: 'html',
        success: function success() {
          if (_.isFunction(successCallback)) {
            successCallback();
          }
        }
      });
    }
  };
  return propertyManager;
});
