define('layout/section-height',['jquery', 'lodash'], function ($, _) {
  'use strict';

  var $versionWarning = $('.version-warning:visible'),
    $window = $(window),
    $footer = $('body > footer');
  function getTreeActionIdealHeight() {
    var $visibleActionBarBox = $('.tree-action-bar-box'),
      $visibleActionBar = $visibleActionBarBox.find('.tree-action-bar'),
      $mainButtons = $visibleActionBar.find('li'),
      $visibleButtons = $mainButtons.filter(':visible'),
      $requiredRows = Math.max(Math.ceil($mainButtons.length / 4), 2),
      idealHeight;
    if (!$visibleButtons.length) {
      $visibleButtons = $('<li class="dummy"><a/></li>');
      $visibleActionBar.append($visibleButtons);
    }
    idealHeight = $visibleButtons.outerHeight(true) * $requiredRows + parseInt($visibleActionBarBox.css('margin-bottom')) + parseInt($visibleActionBarBox.css('margin-top'));
    $visibleActionBarBox.find('.dummy').remove();
    return idealHeight;
  }
  function getContainerHeight($scope) {
    var winHeight = $window.innerHeight(),
      footerHeight = $footer.outerHeight(),
      headerHeight = $('header.main-header').outerHeight() + ($versionWarning.length ? $versionWarning.outerHeight() : 0),
      actionBarHeight = $scope.find('.content-container .action-bar').outerHeight(),
      $tabs = $('.section-container > .tab-container:visible'),
      tabHeight = $tabs.length ? $tabs.outerHeight() : 1;
    return winHeight - headerHeight - footerHeight - actionBarHeight - tabHeight;
  }
  function setHeights($scope) {
    var containerHeight = getContainerHeight($scope),
      $contentBlock = $scope.find('.content-block'),
      $tree = $scope.find('.taotree');
    var treeHeight;
    if (!$tree.length) {
      return;
    }
    $contentBlock.css({
      height: containerHeight,
      maxHeight: containerHeight
    });
    treeHeight = containerHeight - getTreeActionIdealHeight();
    $tree.css({
      maxHeight: treeHeight
    });
    if ($tree.data('type') === 'resource-selector') {
      $tree.css({
        height: treeHeight
      });
    }
  }
  return {
    init: function init($scope) {
      $window.off('resize.sectionheight').on('resize.sectionheight', _.debounce(function () {
        setHeights($scope);
      }, 50));
      $versionWarning.off('hiding.versionwarning').on('hiding.versionwarning', function () {
        $versionWarning = $('.version-warning:visible');
        setHeights($scope);
      });
      $(window).trigger('resize.navheight');
    },
    setHeights: setHeights
  };
});
